import React, { useState, useEffect } from 'react';
import { APIProvider, Map, AdvancedMarker, Pin, InfoWindow, useMap } from '@vis.gl/react-google-maps';
import { MarkerClusterer } from '@googlemaps/markerclusterer';

const defaultLocation = { lat: 10.8231, lng: 106.6297 };

const ClusteredMarkers = ({ markers, onMarkerClick }) => {
  const map = useMap();
  const [clusterer, setClusterer] = useState(null);
  const [markerRefs, setMarkerRefs] = useState({});

  useEffect(() => {
    if (!map) return;
    const cl = new MarkerClusterer({ map });
    setClusterer(cl);
    return () => { cl.clearMarkers(); }
  }, [map]);

  useEffect(() => {
    clusterer?.clearMarkers();
    clusterer?.addMarkers(Object.values(markerRefs).filter(m => m !== null));
  }, [clusterer, markerRefs, markers]);

  const setMarkerRef = (marker, key) => {
    if (marker && markerRefs[key]) return;
    if (!marker && !markerRefs[key]) return;
    setMarkerRefs(prev => {
      if (marker) return { ...prev, [key]: marker };
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  return (
    <>
      {markers.map(m => (
        <AdvancedMarker 
          key={m.key} 
          position={{ lat: m.lat, lng: m.lng }} 
          ref={marker => setMarkerRef(marker, m.key)}
          onClick={() => onMarkerClick(m.data, m.type)}
        >
          {m.pin}
        </AdvancedMarker>
      ))}
    </>
  );
};

const StormShieldMap = ({ shelters = [], reports = [], alerts = [] }) => {
  const [center, setCenter] = useState(defaultLocation);
  const [myLocation, setMyLocation] = useState(null);
  const [selectedElement, setSelectedElement] = useState(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const loc = { lat: position.coords.latitude, lng: position.coords.longitude };
          setMyLocation(loc);
          setCenter(loc);
        },
        () => console.warn("Lỗi xác định vị trí. Đoán mặc định ở TP.HCM.")
      );
    }
  }, []);

  const handleMarkerClick = (element, type) => {
    setSelectedElement({ ...element, elementType: type });
  };

  // Flatten structures for clustering
  const allMarkers = [
    ...shelters.map(s => ({
      key: `s-${s.id}`, lat: s.latitude, lng: s.longitude, data: s, type: 'SHELTER',
      pin: <Pin background={'#10B981'} borderColor={'#065F46'} glyphColor={'#FFFFFF'} />
    })),
    ...reports.map(r => ({
      key: `r-${r.id}`, lat: r.latitude, lng: r.longitude, data: r, type: 'REPORT',
      pin: <Pin background={'#F59E0B'} borderColor={'#92400E'} glyphColor={'#FFFFFF'} />
    })),
    ...alerts.filter(a => a.latitude && a.longitude).map(a => ({
      key: `a-${a.id}`, lat: a.latitude, lng: a.longitude, data: a, type: 'ALERT',
      pin: <Pin background={'#EF4444'} borderColor={'#991B1B'} glyphColor={'#FFFFFF'} />
    }))
  ];

  return (
    <div style={{ height: '500px', width: '100%', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}>
      <APIProvider apiKey={process.env.REACT_APP_GOOGLE_MAPS_API_KEY}>
        <Map defaultZoom={13} center={center} onCenterChanged={(ev) => setCenter(ev.detail.center)} mapId="DEMO_MAP_ID">

          <ClusteredMarkers markers={allMarkers} onMarkerClick={handleMarkerClick} />

          {myLocation && (
            <AdvancedMarker position={myLocation} onClick={() => handleMarkerClick({ lat: myLocation.lat, lng: myLocation.lng, title: 'Bạn đang ở đây' }, 'USER')}>
              <Pin background={'#2563EB'} borderColor={'#FFFFFF'} glyphColor={'#FFFFFF'} />
            </AdvancedMarker>
          )}

          {selectedElement && (
            <InfoWindow
              position={{ lat: selectedElement.lat || selectedElement.latitude, lng: selectedElement.lng || selectedElement.longitude }}
              onCloseClick={() => setSelectedElement(null)}
            >
              <div style={{ padding: '4px', maxWidth: '200px' }}>
                {selectedElement.elementType === 'USER' && <strong style={{color: '#2563EB'}}>{selectedElement.title}</strong>}

                {selectedElement.elementType === 'SHELTER' && (
                  <div>
                    <strong style={{color: '#10B981'}}>{selectedElement.name}</strong><br/>
                    Địa chỉ: {selectedElement.address}<br/>
                    Trạng thái: {selectedElement.status}<br/>
                    Sức chứa: {selectedElement.currentOccupancy}/{selectedElement.capacity}
                  </div>
                )}

                {selectedElement.elementType === 'REPORT' && (
                  <div>
                    <strong style={{color: '#F59E0B'}}>NGUY HIỂM: {selectedElement.reportType}</strong><br/>
                    Mức độ: {selectedElement.dangerLevel}<br/>
                    Chi tiết: {selectedElement.description}
                  </div>
                )}

                {selectedElement.elementType === 'ALERT' && (
                  <div>
                    <strong style={{color: '#EF4444'}}>CẢNH BÁO: {selectedElement.title}</strong><br/>
                    Nghiêm trọng: {selectedElement.severityLevel}<br/>
                    {selectedElement.description}
                  </div>
                )}
              </div>
            </InfoWindow>
          )}
        </Map>
      </APIProvider>
    </div>
  );
};
export default StormShieldMap;
